import React, { useEffect, useState } from "react";
import { Link } from 'react-router-dom';
import API from '../api/axios';
import "../style.css";

function HomePage() {
  const [posts, setPosts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    API.get('/posts')
      .then(res => setPosts(res.data))
      .finally(() => setLoading(false));
  }, []);

  if (loading) return <p style={{textAlign: 'center', padding: '2rem'}}>Loading posts...</p>;

  return (
    <div className="home-page-container">
      {/* Hero Section */}
      <section className="home-hero">
        <h1>Welcome to TheFolio</h1>
        <p>Share Your Creative Portfolio & Connect with the Community</p>
        <Link to="/register" className="cta-button">Get Started</Link>
      </section>

      {/* Feature Cards */}
      <section className="features-section">
        <h2>Why Choose TheFolio?</h2>
        <div className="features-grid">
          <div className="feature-card">
            <div className="feature-icon">📝</div>
            <h3>Share Your Story</h3>
            <p>Create and publish posts about your coding journey, projects, and insights.</p>
          </div>
          <div className="feature-card">
            <div className="feature-icon">❤️</div>
            <h3>Connect & Grow</h3>
            <p>Build relationships with other developers and learn from the community.</p>
          </div>
          <div className="feature-card">
            <div className="feature-icon">✨</div>
            <h3>Inspire Others</h3>
            <p>Share your knowledge and help others on their coding adventure.</p>
          </div>
        </div>
      </section>

      {/* Latest Posts Section */}
      <section className="latest-posts-section">
        <h2>Latest Posts</h2>
        {posts.length === 0 ? (
          <div className="empty-posts" style={{textAlign: 'center', padding: '3rem'}}>
            <p style={{fontSize: '1.1rem', color: '#666'}}>No posts yet. Be the first to share!</p>
            <Link to="/create-post" style={{display: 'inline-block', marginTop: '1rem'}} className="cta-button">Write First Post</Link>
          </div>
        ) : (
          <div className="posts-grid">
            {posts.map(post => (
              <Link to={`/posts/${post._id}`} key={post._id} className="post-card-link">
                <div className="post-card">
                  {post.image && (
                    <div className="post-image">
                      <img src={`http://localhost:5000/uploads/${post.image}`} alt={post.title} />
                    </div>
                  )}
                  <div className="post-content">
                    <h3>{post.title}</h3>
                    <p>{post.body.substring(0, 100)}...</p>
                    <div className="post-meta">
                      <small>By {post.author?.name}</small>
                      <small>{new Date(post.createdAt).toLocaleDateString()}</small>
                    </div>
                  </div>
                </div>
              </Link>
            ))}
          </div>
        )}
      </section>

      {/* CTA Section */}
      <section className="cta-section">
        <h2>Ready to Share Your Portfolio?</h2>
        <p>Join TheFolio today and start building your creative presence</p>
        <Link to="/register" className="cta-button">Join Now</Link>
      </section>

      {/* Footer */}
      <footer className="home-footer">
        <p>© 2026 TheFolio - Share Your Creative Journey</p>
      </footer>
    </div>
  );
}

export default HomePage;
